  ('disabled-e3452428-moex-00289', 'disabled-e3452428', 'disabled-e3452428-moex-111-3082b5f1', 'sub-disabled-e3452428-05', NULL, 'single_choice', '有關國家賠償制度，下列敘述何者錯誤？', '["人民得因國家機關違法行使公權力，受到損害，請求國家賠償", "人民因私人擁有所有權之公共設施受害者，仍得依法請求國家賠償", "人民不得透過行政訴訟程序，請求國家機關賠償因違法行使公權力所致 之損害", "國家賠償之訴，國家賠償法及其施行細則未規定者，適用民事訴訟法相 關規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:18+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
